# --- Secure Token Store ---
# Tokens stored as SHA-256 hashes, never plaintext
class TokenAuthenticator:
    def __init__(self):
        self._authorized_token_hashes = set()
        self._load_token_hashes()

    def _load_token_hashes(self):
        """Load pre-hashed authorized tokens from secure storage."""
        try:
            with open(TOKEN_HASH_FILE, "r") as f:
                for line in f:
                    token_hash = line.strip()
                    if len(token_hash) == 64:  # SHA-256 hex length
                        self._authorized_token_hashes.add(token_hash)
        except OSError:
            # First boot: create file with a default provisioned token hash
            # In production, tokens are provisioned via secure enrollment
            default_hash = hashlib.sha256(b"CHANGE_ME_ON_PROVISION").hexdigest()
            self._authorized_token_hashes.add(default_hash)
            self._save_token_hashes()

    def _save_token_hashes(self):
        try:
            with open(TOKEN_HASH_FILE, "w") as f:
                for h in self._authorized_token_hashes:
                    f.write(h + "\n")
        except OSError:
            pass

    def is_authorized(self, token_bytes):
        """Validate token by comparing hash. Never stores or logs raw token."""
        if not token_bytes or len(token_bytes) > 128:
            return False
        token_hash = hashlib.sha256(token_bytes).hexdigest()
        return token_hash in self._authorized_token_hashes

    def add_token_hash(self, token_hash_hex):
        """Add a pre-hashed token (for provisioning)."""
        if isinstance(token_hash_hex, str) and len(token_hash_hex) == 64:
            self._authorized_token_hashes.add(token_hash_hex)
            self._save_token_hashes()


# --- Rate Limiter ---
class RateLimiter:
    def __init__(self, max_requests_per_sec=REQUEST_RATE_LIMIT):
        self._max_rps = max_requests_per_sec
        self._client_requests = {}  # ip -> (count, window_start)

    def is_allowed(self, client_ip):
        """Simple sliding window rate limiter."""
        if not client_ip:
            return False
        now = time.ticks_ms()
        if client_ip in self._client_requests:
            count, window_start = self._client_requests[client_ip]
            elapsed = time.ticks_diff(now, window_start)
            if elapsed < 1000:
                if count >= self._max_rps:
                    return False
                self._client_requests[client_ip] = (count + 1, window_start)
            else:
                self._client_requests[client_ip] = (1, now)
        else:
            # Limit tracked clients to prevent memory exhaustion
            if len(self._client_requests) > 50:
                self._client_requests.clear()
            self._client_requests[client_ip] = (1, now)
        return True


# --- Input Validation ---
class InputValidator:
    # Allowlisted resource paths
    ALLOWED_PATHS = frozenset([
        "sensors/temp",
        "actuators/light",
        "well-known/core",
    ])

    # Allowed methods per resource (least privilege)
    RESOURCE_PERMISSIONS = {
        "sensors/temp": frozenset(["GET"]),
        "actuators/light": frozenset(["GET", "PUT"]),
        "well-known/core": frozenset(["GET"]),
    }

    @staticmethod
    def validate_path(path):
        """Validate path against explicit allowlist."""
        if not isinstance(path, str):
            return None
        # Normalize: strip leading/trailing slashes, collapse doubles
        cleaned = path.strip("/").replace("//", "/")
        # Reject path traversal attempts
        if ".." in cleaned or "~" in cleaned:
            return None
        if cleaned in InputValidator.ALLOWED_PATHS:
            return cleaned
        return None

    @staticmethod
    def is_method_allowed(path, method):
        """Check if method is allowed for the given resource."""
        perms = InputValidator.RESOURCE_PERMISSIONS.get(path)
        if perms is None:
            return False
        return method in perms

    @staticmethod
    def validate_light_payload(payload):
        """Validate and sanitize actuator/light PUT payload."""
        if not payload or len(payload) > MAX_PAYLOAD_SIZE:
            return None
        try:
            if isinstance(payload, (bytes, bytearray)):
                payload = payload.decode("utf-8")
            data = json.loads(payload)
        except (ValueError, UnicodeError):
            return None

        # Strict schema validation
        if not isinstance(data, dict):
            return None

        result = {}

        # Validate 'state' field: must be bool or 0/1
        if "state" in data:
            state = data["state"]
            if isinstance(state, bool):
                result["state"] = state
            elif state in (0, 1):
                result["state"] = bool(state)
            else:
                return None

        # Validate 'brightness' field: integer 0-100
        if "brightness" in data:
            brightness = data["brightness"]
            if isinstance(brightness, int) and 0 <= brightness <= 100:
                result["brightness"] = brightness
            else:
                return None

        # Reject unknown fields
        allowed_fields = {"state", "brightness"}
        if set(data.keys()) - allowed_fields:
            return None

        if not result:
            return None

        return result


# --- Device Resources ---
class SensorManager:
    """Manages device sensor readings."""

    def __init__(self):
        self._last_temp_read = 0
        self._cached_temp = None
        self._min_read_interval_ms = 500  # Don't read sensor too frequently

    def read_temperature(self):
        """Read temperature from hardware sensor with caching."""
        now = time.ticks_ms()
        if (self._cached_temp is not None and
                time.ticks_diff(now, self._last_temp_read) < self._min_read_interval_ms):
            return self._cached_temp

        try:
            # Use internal temperature sensor on RP2040/ESP32
            # Adjust for your specific hardware
            adc = machine.ADC(4)  # Internal temp sensor on RP2040
            raw = adc.read_u16()
            # Convert to Celsius (RP2040 formula)
            voltage = raw * 3.3 / 65535
            temp_c = 27.0 - (voltage - 0.706) / 0.001721
            temp_c = round(temp_c, 2)
            # Sanity check: reject obviously wrong readings
            if -40.0 <= temp_c <= 85.0:
                self._cached_temp = temp_c
                self._last_temp_read = now
                return temp_c
            else:
                return self._cached_temp  # Return last good reading
        except Exception:
            # Hardware read failure - return cached or None
            return self._cached_temp


class ActuatorManager:
    """Manages device actuators with state validation."""

    def __init__(self):
        self._light_state = False
        self._light_brightness = 0
        self._light_pin = None
        self._pwm = None
        self._init_hardware()

    def _init_hardware(self):
        """Initialize light actuator hardware."""
        try:
            self._light_pin = machine.Pin(2, machine.Pin.OUT)
            self._pwm = machine.PWM(self._light_pin)
            self._pwm.freq(1000)
            self._pwm.duty_u16(0)
        except Exception:
            self._light_pin = None
            self._pwm = None

    def get_light_state(self):
        return {
            "state": self._light_state,
            "brightness": self._light_brightness,
        }

    def set_light_state(self, validated_data):
        """Set light state from pre-validated data."""
        if "state" in validated_data:
            self._light_state = validated_data["state"]

        if "brightness" in validated_data:
            self._light_brightness = validated_data["brightness"]

        # Apply to hardware
        self._apply_hardware_state()
        return self.get_light_state()

    def _apply_hardware_state(self):
        """Apply current state to hardware."""
        if self._pwm is None:
            return
        try:
            if not self._light_state:
                self._pwm.duty_u16(0)
            else:
                duty = int(self._light_brightness * 65535 / 100)
                self._pwm.duty_u16(duty)
        except Exception:
            pass


# --- CoAP Response Codes ---
class CoapCodes:
    CONTENT = 69          # 2.05
    CHANGED = 68          # 2.04
    BAD_REQUEST = 128     # 4.00
    UNAUTHORIZED = 129    # 4.01
    FORBIDDEN = 131       # 4.03
    NOT_FOUND = 132       # 4.04
    METHOD_NOT_ALLOWED = 133  # 4.05
    TOO_MANY_REQUESTS = 157  # 4.29
    INTERNAL_ERROR = 160  # 5.00


# --- CoAP Server ---
class SecureCoapServer:
    def __init__(self, port=COAP_PORT):
        self._port = port
        self._coap = microcoapy.Coap()
        self._authenticator = TokenAuthenticator()
        self._rate_limiter = RateLimiter()
        self._sensor_mgr = SensorManager()
        self._actuator_mgr = ActuatorManager()
        self._setup_resources()

    def _setup_resources(self):
        """Register CoAP resource handlers."""
        self._coap.addIncomingRequestCallback(self._handle_request)

    def _extract_auth_token(self, packet):
        """Extract authentication token from CoAP option.
        Uses Option 256 (vendor-specific) for auth token.
        Never logs or prints the token value."""
        try:
            if hasattr(packet, 'options'):
                for opt in packet.options:
                    if opt.number == 256:
                        return opt.value
        except Exception:
            pass
        return None

    def _get_method_name(self, packet):
        """Extract CoAP method from packet code."""
        code = packet.code if hasattr(packet, 'code') else None
        method_map = {1: "GET", 2: "POST", 3: "PUT", 4: "DELETE"}
        return method_map.get(code, None)

    def _handle_request(self, packet, sender):
        """Main request handler with security checks."""
        client_ip = sender[0] if sender else "unknown"

        # 1. Rate limiting
        if not self._rate_limiter.is_allowed(client_ip):
            self._send_error(packet, sender, CoapCodes.TOO_MANY_REQUESTS,
                             "Rate limit exceeded")
            return

        # 2. Authentication
        token = self._extract_auth_token(packet)
        if not self._authenticator.is_authorized(token):
            self._send_error(packet, sender, CoapCodes.UNAUTHORIZED,
                             "Unauthorized")
            return

        # 3. Path validation (allowlist)
        raw_path = ""
        if hasattr(packet, 'url') and packet.url:
            raw_path = packet.url
        elif hasattr(packet, 'options'):
            # Reconstruct path from Uri-Path options
            path_parts = []
            for opt in packet.options:
                if opt.number == 11:  # Uri-Path
                    if isinstance(opt.value, bytes):
                        path_parts.append(opt.value.decode("utf-8", "replace"))
                    else:
                        path_parts.append(str(opt.value))
            raw_path = "/".join(path_parts)

        validated_path = InputValidator.validate_path(raw_path)
        if validated_path is None:
            self._send_error(packet, sender, CoapCodes.NOT_FOUND,
                             "Resource not found")
            return

        # 4. Method validation (least privilege per resource)
        method = self._get_method_name(packet)
        if method is None or not InputValidator.is_method_allowed(validated_path, method):
            self._send_error(packet, sender, CoapCodes.METHOD_NOT_ALLOWED,
                             "Method not allowed")
            return

        # 5. Route to handler
        try:
            if validated_path == "sensors/temp":
                self._handle_temp(packet, sender, method)
            elif validated_path == "actuators/light":
                self._handle_light(packet, sender, method)
            elif validated_path == "well-known/core":
                self._handle_discovery(packet, sender)
            else:
                self._send_error(packet, sender, CoapCodes.NOT_FOUND,
                                 "Resource not found")
        except Exception:
            self._send_error(packet, sender, CoapCodes.INTERNAL_ERROR,
                             "Internal error")

    def _handle_temp(self, packet, sender, method):
        """Handle /sensors/temp GET requests."""
        temp = self._sensor_mgr.read_temperature()
        if temp is not None:
            payload = json.dumps({"temperature_c": temp, "unit": "celsius"})
            self._send_response(packet, sender, CoapCodes.CONTENT, payload)
        else:
            self._send_error(packet, sender, CoapCodes.INTERNAL_ERROR,
                             "Sensor unavailable")

    def _handle_light(self, packet, sender, method):
        """Handle /actuators/light GET and PUT requests."""
        if method == "GET":
            state = self._actuator_mgr.get_light_state()
            payload = json.dumps(state)
            self._send_response(packet, sender, CoapCodes.CONTENT, payload)

        elif method == "PUT":
            # Validate payload
            raw_payload = packet.payload if hasattr(packet, 'payload') else None
            validated_data = InputValidator.validate_light_payload(raw_payload)
            if validated_data is None:
                self._send_error(packet, sender, CoapCodes.BAD_REQUEST,
                                 "Invalid payload")
                return

            new_state = self._actuator_mgr.set_light_state(validated_data)
            payload = json.dumps(new_state)
            self._send_response(packet, sender, CoapCodes.CHANGED, payload)

    def _handle_discovery(self, packet, sender):
        """Handle /.well-known/core for CoAP resource discovery."""
        links = (
            '</sensors/temp>;rt="temperature";if="sensor";ct=50,'
            '</actuators/light>;rt="light";if="actuator";ct=50'
        )
        self._send_response(packet, sender, CoapCodes.CONTENT, links,
                            content_format=40)  # application/link-format

    def _send_response(self, packet, sender, code, payload,
                       content_format=50):
        """Send CoAP response with payload."""
        try:
            if isinstance(payload, str):
                payload = payload.encode("utf-8")
            self._coap.sendResponse(
                sender,
                packet.messageid,
                payload,
                code,
                content_format,
                packet.token
            )
        except Exception:
            pass

    def _send_error(self, packet, sender, code, message):
        """Send CoAP error response. Never include internal details."""
        # Only send generic error messages, no stack traces or internals
        safe_messages = {
            CoapCodes.BAD_REQUEST: "Bad request",
            CoapCodes.UNAUTHORIZED: "Unauthorized",
            CoapCodes.FORBIDDEN: "Forbidden",
            CoapCodes.NOT_FOUND: "Not found",
            CoapCodes.METHOD_NOT_ALLOWED: "Method not allowed",
            CoapCodes.TOO_MANY_REQUESTS: "Too many requests",
            CoapCodes.INTERNAL_ERROR: "Server error",
        }
        safe_msg = safe_messages.get(code, "Error")
        try:
            self._coap.sendResponse(
                sender,
                packet.messageid if hasattr(packet, 'messageid') else 0,
                safe_msg.encode("utf-8"),
                code,
                0,  # text/plain
                packet.token if hasattr(packet, 'token') else b""
            )
        except Exception:
            pass

    def start(self):
        """Start the CoAP server."""
        print("Starting Secure CoAP Server on port", self._port)
        self._coap.start(port=self._port)
        print("CoAP Server listening...")

        try:
            while True:
                self._coap.poll(timeout_ms=1000)
                # Periodic maintenance
                time.sleep_ms(10)
        except KeyboardInterrupt:
            print("Server shutting down...")
        finally:
            self._coap.stop()


# --- Network Setup ---
def connect_wifi(ssid, password_env_key="WIFI_PASS"):
    """Connect to WiFi. Password should be stored securely,
    not hardcoded. Uses environment variable or secure storage."""
    import network
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)

    # In production, retrieve password from secure element or
    # encrypted NVS partition, never from source code
    password = None
    try:
        # Try to read from a secure config file (should be encrypted at rest)
        with open("wifi_cred.enc", "rb") as f:
            # In real implementation, decrypt with hardware key
            cred_data = f.read()
            # Placeholder: in production use proper decryption
            password = cred_data.decode("utf-8").strip()
    except OSError:
        print("ERROR: WiFi credentials not provisioned securely.")
        print("Please provision credentials via secure enrollment.")
        return None

    if not password:
        print("ERROR: No WiFi password available.")
        return None

    if not wlan.isconnected():
        wlan.connect(ssid, password)
        # Clear password from memory
        password = None

        timeout = 10000
        start = time.ticks_ms()
        while not wlan.isconnected():
            if time.ticks_diff(time.ticks_ms(), start) > timeout:
                print("WiFi connection timeout")
                return None
            time.sleep_ms(100)

    config = wlan.ifconfig()
    print("Connected. IP:", config[0])
    return config[0]


# --- Provisioning Helper ---
def provision_auth_token(raw_token):
    """Provision a new auth token by storing only its hash.
    Call this during secure device enrollment.
    The raw token is never stored."""
    if not raw_token or len(raw_token) < 16:
        print("Token must be at least 16 characters")
        return False

    if isinstance(raw_token, str):
        raw_token = raw_token.encode("utf-8")

    token_hash = hashlib.sha256(raw_token).hexdigest()

    auth = TokenAuthenticator()
    auth.add_token_hash(token_hash)

    # Clear raw token from memory
    raw_token = None
    print("Token provisioned (hash stored, raw token discarded)")
    return True


